  'ep138-03': { originStory: '손(扌)으로 지아비(夫)를 부축해 일으켜 준다는 데서, ‘돕다, 부축하다’를 뜻한다.', vocabulary: [{ word: '扶助 (부조)', meaning: '남을 거들어 도와줌' }, { word: '扶養 (부양)', meaning: '생활을 돌보아 기름' }], radical: '手', strokeCount: 7 },
  'ep138-04': { originStory: '사람(亻)이 머리(頃)를 기울여 한쪽으로 쏠린다는 데서, ‘기울다’를 뜻한다.', vocabulary: [{ word: '傾斜 (경사)', meaning: '비스듬히 기울어짐' }, { word: '傾向 (경향)', meaning: '한쪽으로 쏠리는 성향' }], radical: '人', strokeCount: 13 },

  /* 139 綺回漢惠 */
  'ep139-01': { originStory: '실(糸)로 기이한(奇) 무늬를 놓아 짠 고운 천이라는 데서, ‘비단’을 뜻한다.', vocabulary: [{ word: '綺羅 (기라)', meaning: '곱고 화려한 비단' }], radical: '糸', strokeCount: 14 },
  'ep139-02': { originStory: '물이 빙빙 돌아 소용돌이치는 모양을 본뜬 데서, ‘돌다, 돌아오다’를 뜻한다.', vocabulary: [{ word: '回轉 (회전)', meaning: '빙빙 돎' }, { word: '回復 (회복)', meaning: '본래대로 돌아옴' }], radical: '囗', strokeCount: 6 },
  'ep139-03': { originStory: '물(氵)이 크게(堇 모양) 흐르는 강이라는 데서, ‘한수, 한나라, 사나이’를 뜻한다.', vocabulary: [{ word: '漢字 (한자)', meaning: '중국에서 만든 문자' }, { word: '漢江 (한강)', meaning: '서울을 흐르는 강 이름' }], radical: '水', strokeCount: 14 },
  'ep139-04': { originStory: '오로지(專 모양) 한마음(心)으로 베푸는 어진 마음이라는 데서, ‘은혜, 사랑’을 뜻한다.', vocabulary: [{ word: '恩惠 (은혜)', meaning: '베풀어 주는 고마운 혜택' }, { word: '惠澤 (혜택)', meaning: '은혜와 덕택' }], radical: '心', strokeCount: 12 },

  /* 140 說感武丁 */
  'ep140-01': { originStory: '말(言)을 풀어내어(兌) 기쁘게 한다는 데서, ‘기쁘다, 말씀, 달래다’를 뜻한다.', vocabulary: [{ word: '說明 (설명)', meaning: '알기 쉽게 풀어 밝힘' }, { word: '說話 (설화)', meaning: '예부터 전해 오는 이야기' }], radical: '言', strokeCount: 14 },
  'ep140-02': { originStory: '온통(咸) 마음(心)을 울려 움직인다는 데서, ‘느끼다, 감동하다’를 뜻한다.', vocabulary: [{ word: '感情 (감정)', meaning: '느끼어 일어나는 마음' }, { word: '感動 (감동)', meaning: '깊이 느껴 마음이 움직임' }], radical: '心', strokeCount: 13 },
  'ep140-03': { originStory: '창(戈)을 들고 멈출(止) 데를 알아 난을 그친다는 데서, ‘굳세다, 무력, 무사’를 뜻한다.', vocabulary: [{ word: '武力 (무력)', meaning: '군사상의 힘' }, { word: '武士 (무사)', meaning: '무예를 닦은 사람' }], radical: '止', strokeCount: 8 },
  'ep140-04': { originStory: '못을 박아 놓은 고무래의 모양을 본뜬 데서, ‘고무래, 장정, 넷째 천간’을 뜻한다.', vocabulary: [{ word: '丁男 (정남)', meaning: '한창때의 장정' }, { word: '兵丁 (병정)', meaning: '병사' }], radical: '一', strokeCount: 2 },

  /* 141 俊乂密勿 */
  'ep141-01': { originStory: '사람(亻)이 무리 가운데 빼어나게(夋) 뛰어나다는 데서, ‘준걸, 뛰어나다’를 뜻한다.', vocabulary: [{ word: '俊傑 (준걸)', meaning: '재주가 뛰어난 사람' }, { word: '俊秀 (준수)', meaning: '재주와 풍채가 빼어남' }], radical: '人', strokeCount: 9 },
  'ep141-02': { originStory: '풀을 베듯 어지러운 것을 잘라 다스린다는 데서, ‘베다, 다스리다, 어질다’를 뜻한다.', vocabulary: [{ word: '俊乂 (준예)', meaning: '재주와 덕이 뛰어난 사람' }], radical: '丿', strokeCount: 2 },
  'ep141-03': { originStory: '산(山)으로 둘러싸인 집(宀)처럼 빈틈없이(必) 깊고 빽빽하다는 데서, ‘빽빽하다, 은밀하다’를 뜻한다.', vocabulary: [{ word: '密集 (밀집)', meaning: '빽빽하게 모임' }, { word: '秘密 (비밀)', meaning: '숨겨 남에게 알리지 않는 일' }], radical: '宀', strokeCount: 11 },
  'ep141-04': { originStory: '깃발이 바람에 펄럭이는 모양에서, 깃발로 금하는 데서 ‘말다, 아니다’를 뜻한다.', vocabulary: [{ word: '勿論 (물론)', meaning: '말할 것도 없이' }], radical: '勹', strokeCount: 4 },

  /* 142 多士寔寧 */
  'ep142-01': { originStory: '저녁(夕)이 거듭 쌓여 날이 늘어난다는 데서, ‘많다’를 뜻한다.', vocabulary: [{ word: '多數 (다수)', meaning: '수효가 많음' }, { word: '多樣 (다양)', meaning: '여러 가지로 많음' }], radical: '夕', strokeCount: 6 },
  'ep142-02': { originStory: '하나(一)에서 열(十)까지 두루 통달한 사람이라는 데서, ‘선비, 벼슬아치’를 뜻한다.', vocabulary: [{ word: '士兵 (사병)', meaning: '하급 군인' }, { word: '學士 (학사)', meaning: '학문을 닦은 사람, 학위' }], radical: '士', strokeCount: 3 },
  'ep142-03': { originStory: '집(宀) 안에 참된(是) 사실이 분명히 있다는 데서, ‘이것, 참으로’를 뜻한다.', vocabulary: [{ word: '寔事 (식사)', meaning: '참된 일, 사실인 일' }], radical: '宀', strokeCount: 12 },
  'ep142-04': { originStory: '집(宀) 안에서 마음(心)이 그릇(皿)에 담긴 듯 편안하다는 데서, ‘편안하다’를 뜻한다.', vocabulary: [{ word: '安寧 (안녕)', meaning: '아무 탈 없이 편안함' }, { word: '寧靜 (영정)', meaning: '편안하고 고요함' }], radical: '宀', strokeCount: 14 },

  /* 143 晉楚更霸 */
  'ep143-01': { originStory: '해(日)가 떠올라 만물이 함께(臸) 나아간다는 데서, ‘나아가다, 진나라’를 뜻한다.', vocabulary: [{ word: '晉州 (진주)', meaning: '경상남도의 지명' }], radical: '日', strokeCount: 10 },
  'ep143-02': { originStory: '가시 돋친 떨기나무(林)가 발(疋)을 찌르는 가시나무라는 데서, ‘초나라, 회초리, 가시’를 뜻한다.', vocabulary: [{ word: '楚撻 (초달)', meaning: '회초리로 종아리를 때림' }, { word: '苦楚 (고초)', meaning: '괴로움과 어려움' }], radical: '木', strokeCount: 13 },
  'ep143-03': { originStory: '고치고(攵) 또 고쳐 거듭한다는 데서, ‘다시, 고치다’를 뜻한다.', vocabulary: [{ word: '更新 (갱신)', meaning: '다시 새롭게 함' }, { word: '變更 (변경)', meaning: '바꾸어 고침' }], radical: '曰', strokeCount: 7 },
  'ep143-04': { originStory: '비(雨)에 젖었다 마른 가죽(革)처럼 달(月)이 처음 빛을 내듯, 으뜸가는 ‘으뜸, 우두머리’를 뜻한다.', vocabulary: [{ word: '霸權 (패권)', meaning: '으뜸의 자리를 차지한 권력' }, { word: '霸者 (패자)', meaning: '으뜸으로 세력을 떨친 사람' }], radical: '雨', strokeCount: 21 },

  /* 144 趙魏困橫 */
