  'ep144-02': { originStory: '높이 솟은(委) 도깨비(鬼)처럼 우뚝하다는 데서, 높고 큰 ‘위나라’를 뜻한다.', vocabulary: [{ word: '魏闕 (위궐)', meaning: '대궐의 정문 위 누각' }], radical: '鬼', strokeCount: 18 },
  'ep144-03': { originStory: '에워싼(囗) 울 안에 나무(木)가 갇혀 자라지 못한다는 데서, ‘곤하다, 괴롭다’를 뜻한다.', vocabulary: [{ word: '困難 (곤란)', meaning: '몹시 어렵고 딱함' }, { word: '貧困 (빈곤)', meaning: '가난하여 살기 어려움' }], radical: '囗', strokeCount: 7 },
  'ep144-04': { originStory: '나무(木)를 누렇게(黃) 가로질러 놓는다는 데서, ‘가로지르다, 비끼다’를 뜻한다.', vocabulary: [{ word: '橫斷 (횡단)', meaning: '가로질러 건넘' }, { word: '縱橫 (종횡)', meaning: '세로와 가로' }], radical: '木', strokeCount: 16 },

  /* 145 假途滅虢 */
  'ep145-01': { originStory: '사람(亻)이 빌려(叚) 임시로 꾸민다는 데서, ‘거짓, 빌리다, 임시’를 뜻한다.', vocabulary: [{ word: '假面 (가면)', meaning: '거짓으로 꾸민 탈' }, { word: '假令 (가령)', meaning: '예를 들어, 설령' }], radical: '人', strokeCount: 11 },
  'ep145-02': { originStory: '쉬엄쉬엄 가며(辶) 남는(余) 길을 따라 나아간다는 데서, ‘길’을 뜻한다.', vocabulary: [{ word: '途中 (도중)', meaning: '길을 가는 중간' }, { word: '前途 (전도)', meaning: '앞으로 나아갈 길, 장래' }], radical: '辵', strokeCount: 11 },
