  'ep145-04': { originStory: '범(虎)이 손톱(寽)으로 움켜쥐듯 사나운 나라라는 데서, ‘괵나라’를 뜻한다.', vocabulary: [{ word: '虢國 (괵국)', meaning: '주나라 때의 제후국 이름' }], radical: '虍', strokeCount: 15 },

  /* 146 踐土會盟 */
  'ep146-01': { originStory: '발(足)로 적은(戔) 자취를 디뎌 밟는다는 데서, ‘밟다, 행하다’를 뜻한다.', vocabulary: [{ word: '實踐 (실천)', meaning: '실제로 행함' }, { word: '踐踏 (천답)', meaning: '발로 밟음' }], radical: '足', strokeCount: 15 },
  'ep146-02': { originStory: '땅에서 싹이 돋아 솟은 흙더미의 모양을 본뜬 데서, ‘흙, 땅’을 뜻한다.', vocabulary: [{ word: '土地 (토지)', meaning: '사람이 사는 땅' }, { word: '土壤 (토양)', meaning: '식물이 자라는 흙' }], radical: '土', strokeCount: 3 },
  'ep146-03': { originStory: '뚜껑(亼)을 덮어(曾) 여러 가지를 한데 모은다는 데서, ‘모이다, 만나다’를 뜻한다.', vocabulary: [{ word: '會議 (회의)', meaning: '여럿이 모여 의논함' }, { word: '集會 (집회)', meaning: '여러 사람이 모임' }], radical: '曰', strokeCount: 13 },
  'ep146-04': { originStory: '밝은(明) 해와 달 앞에 피(血)를 나눠 마시며 약속한다는 데서, ‘맹세하다’를 뜻한다.', vocabulary: [{ word: '盟誓 (맹세)', meaning: '굳게 약속함' }, { word: '同盟 (동맹)', meaning: '함께 행동하기로 맺은 약속' }], radical: '皿', strokeCount: 13 },

  /* 147 何遵約法 */
