  'ep147-02': { originStory: '높은(尊) 길을 따라(辶) 쫓아 지킨다는 데서, ‘좇다, 따르다’를 뜻한다.', vocabulary: [{ word: '遵守 (준수)', meaning: '규칙이나 명령을 좇아 지킴' }, { word: '遵法 (준법)', meaning: '법을 좇아 지킴' }], radical: '辵', strokeCount: 15 },
  'ep147-03': { originStory: '실(糸)을 묶듯 작은(勺) 약속으로 매듭짓는다는 데서, ‘맺다, 약속, 줄이다’를 뜻한다.', vocabulary: [{ word: '約束 (약속)', meaning: '서로 정하여 어기지 않기로 함' }, { word: '契約 (계약)', meaning: '법적 효력을 가진 약속' }], radical: '糸', strokeCount: 9 },
  'ep147-04': { originStory: '물(氵)이 흐르듯 공평하게 나아가게(去) 한 본보기라는 데서, ‘법’을 뜻한다.', vocabulary: [{ word: '法律 (법률)', meaning: '나라가 정한 규범' }, { word: '方法 (방법)', meaning: '일을 해 나가는 수단' }], radical: '水', strokeCount: 8 },

  /* 148 韓弊煩刑 */
  'ep148-01': { originStory: '해 돋는 아침(倝) 우물(韋)을 두른 두레박틀처럼 둘러친 데서, ‘한나라, 한국’을 뜻한다.', vocabulary: [{ word: '韓國 (한국)', meaning: '우리나라의 이름' }, { word: '韓服 (한복)', meaning: '우리나라 고유의 옷' }], radical: '韋', strokeCount: 17 },
  'ep148-02': { originStory: '해진(敝) 천처럼 닳고 무너진다는 데서, ‘해지다, 폐단, 나쁘다’를 뜻한다.', vocabulary: [{ word: '弊端 (폐단)', meaning: '나쁘고 해로운 일' }, { word: '弊害 (폐해)', meaning: '폐단으로 생기는 해' }], radical: '廾', strokeCount: 15 },
  'ep148-03': { originStory: '불(火)에 머리(頁)가 달아오르듯 어수선하다는 데서, ‘번거롭다, 괴롭다’를 뜻한다.', vocabulary: [{ word: '煩惱 (번뇌)', meaning: '마음을 괴롭히는 망상' }, { word: '頻煩 (빈번)', meaning: '잦고 번거로움' }], radical: '火', strokeCount: 13 },
  'ep148-04': { originStory: '우물틀(开)처럼 정한 틀로 칼(刂)을 써서 죄를 다스린다는 데서, ‘형벌’을 뜻한다.', vocabulary: [{ word: '刑罰 (형벌)', meaning: '죄지은 사람에게 주는 벌' }, { word: '處刑 (처형)', meaning: '형벌에 처함' }], radical: '刀', strokeCount: 6 },

  /* 149 起翦頗牧 */
  'ep149-01': { originStory: '몸(走)을 일으켜 자기(己)가 떨쳐 일어선다는 데서, ‘일어나다, 비롯하다’를 뜻한다.', vocabulary: [{ word: '起立 (기립)', meaning: '일어나 섬' }, { word: '起源 (기원)', meaning: '사물이 비롯된 근원' }], radical: '走', strokeCount: 10 },
  'ep149-02': { originStory: '깃(羽)을 가지런히(前) 잘라 다듬는다는 데서, ‘자르다, 베다, 멸하다’를 뜻한다.', vocabulary: [{ word: '翦滅 (전멸)', meaning: '베어 모두 없앰' }], radical: '羽', strokeCount: 15 },
  'ep149-03': { originStory: '머리(頁)가 한쪽으로 기울어 치우쳐(皮) 있다는 데서, ‘자못, 치우치다’를 뜻한다.', vocabulary: [{ word: '偏頗 (편파)', meaning: '한쪽으로 치우쳐 공정하지 못함' }], radical: '頁', strokeCount: 14 },
  'ep149-04': { originStory: '소(牛)를 채찍질(攵)하며 들에서 기른다는 데서, ‘치다, 기르다, 다스리다’를 뜻한다.', vocabulary: [{ word: '牧場 (목장)', meaning: '가축을 놓아 기르는 곳' }, { word: '牧畜 (목축)', meaning: '가축을 기름' }], radical: '牛', strokeCount: 8 },

  /* 150 用軍最精 */
  'ep150-01': { originStory: '점(卜)친 대로 그릇(用 모양)을 골라 쓴다는 데서, ‘쓰다, 부리다’를 뜻한다.', vocabulary: [{ word: '使用 (사용)', meaning: '물건을 씀' }, { word: '用途 (용도)', meaning: '쓰이는 곳' }], radical: '用', strokeCount: 5 },
