  'ep159-02': { originStory: '물(氵)이 흘러 들어 갈라지지(也) 않고 고인 곳이라는 데서, ‘못’을 뜻한다.', vocabulary: [{ word: '貯水池 (저수지)', meaning: '물을 모아 두는 못' }, { word: '電池 (전지)', meaning: '전기를 저장하는 장치' }], radical: '氵', strokeCount: 6 },
  'ep159-03': { originStory: '돌(石)을 우뚝하게(曷) 세워 글을 새긴 데서, ‘비석, 빗돌’을 뜻한다.', vocabulary: [{ word: '碣石 (갈석)', meaning: '둥글게 다듬어 세운 비석' }, { word: '墓碣 (묘갈)', meaning: '무덤 앞에 세운 작은 비석' }], radical: '石', strokeCount: 14 },
  'ep159-04': { originStory: '언덕(厂) 아래 굴러떨어진 단단한 덩어리(口)를 본떠, ‘돌’을 뜻한다.', vocabulary: [{ word: '石塔 (석탑)', meaning: '돌로 쌓은 탑' }, { word: '寶石 (보석)', meaning: '귀하고 아름다운 돌' }], radical: '石', strokeCount: 5 },
  /* 160 鉅野洞庭 */
  'ep160-01': { originStory: '쇠(金) 가운데서도 크고 단단한(巨) 무쇠라는 데서, ‘크다, 강한 쇠’를 뜻한다.', vocabulary: [{ word: '鉅野 (거야)', meaning: '아주 넓은 들판' }, { word: '鉅儒 (거유)', meaning: '학식이 크고 깊은 선비' }], radical: '金', strokeCount: 13 },
  'ep160-02': { originStory: '마을(里)에서 멀리 떨어져 함부로 펼쳐진(予) 땅이라는 데서, ‘들, 들판’을 뜻한다.', vocabulary: [{ word: '野生 (야생)', meaning: '들에서 절로 자람' }, { word: '原野 (원야)', meaning: '넓은 들판' }], radical: '里', strokeCount: 11 },
  'ep160-03': { originStory: '물(氵)이 한곳으로 같이(同) 모여 깊이 뚫린 곳이라는 데서, ‘골, 고을, 꿰뚫다’를 뜻한다.', vocabulary: [{ word: '洞窟 (동굴)', meaning: '깊고 넓은 굴' }, { word: '洞察 (통찰)', meaning: '꿰뚫어 환히 살핌' }], radical: '氵', strokeCount: 9 },
  'ep160-04': { originStory: '집(广) 안에서 똑바로 펼쳐진(廷) 빈 마당이라는 데서, ‘뜰, 마당’을 뜻한다.', vocabulary: [{ word: '庭園 (정원)', meaning: '집 안에 가꾼 뜰' }, { word: '家庭 (가정)', meaning: '한 가족이 이루는 집안' }], radical: '广', strokeCount: 10 },
  /* 161 曠遠綿邈 */
  'ep161-01': { originStory: '해(日)가 넓게(廣) 비쳐 거칠 것 없이 트인 데서, ‘비다, 넓다, 휑하다’를 뜻한다.', vocabulary: [{ word: '曠野 (광야)', meaning: '아득히 넓고 텅 빈 들' }, { word: '曠日 (광일)', meaning: '하는 일 없이 헛되이 날을 보냄' }], radical: '日', strokeCount: 19 },
  'ep161-02': { originStory: '옷자락 끄는(袁) 발걸음(辶)이 길게 이어진다는 데서, ‘멀다’를 뜻한다.', vocabulary: [{ word: '遠近 (원근)', meaning: '멀고 가까움' }, { word: '永遠 (영원)', meaning: '끝없이 이어짐' }], radical: '辶', strokeCount: 14 },
  'ep161-03': { originStory: '실(糸)을 이어 붙여(帛) 길게 끊이지 않는다는 데서, ‘솜, 이어지다, 잇다’를 뜻한다.', vocabulary: [{ word: '綿絲 (면사)', meaning: '솜으로 자은 실' }, { word: '連綿 (연면)', meaning: '죽 잇따라 끊이지 않음' }], radical: '糸', strokeCount: 14 },
  'ep161-04': { originStory: '얼굴(貌)이 아득해질 만큼 걸어가도(辶) 끝이 없다는 데서, ‘멀다, 아득하다’를 뜻한다.', vocabulary: [{ word: '綿邈 (면막)', meaning: '아득히 멀고 끝없음' }, { word: '邈然 (막연)', meaning: '아득히 멀어 흐릿함' }], radical: '辶', strokeCount: 17 },
