  'ep162-02': { originStory: '산(山)에서 골짜기로 말미암아(由) 굽이쳐 솟은 봉우리라는 데서, ‘묏부리, 산봉우리’를 뜻한다.', vocabulary: [{ word: '岫雲 (수운)', meaning: '산봉우리에 걸린 구름' }, { word: '峀岫 (수수)', meaning: '겹겹의 산봉우리' }], radical: '山', strokeCount: 8 },
  'ep162-03': { originStory: '해(日)가 나무(木) 아래로 잠겨 어두워진다는 데서, ‘아득하다, 깊다’를 뜻한다.', vocabulary: [{ word: '杳然 (묘연)', meaning: '아득하여 알 길이 없음' }, { word: '杳冥 (묘명)', meaning: '아득하고 어두컴컴함' }], radical: '木', strokeCount: 8 },
  'ep162-04': { originStory: '해(日)가 덮여(冖) 빛이 가려진(六) 모습에서, ‘어둡다, 깊다’를 뜻한다.', vocabulary: [{ word: '冥福 (명복)', meaning: '죽은 뒤 저승에서 받는 복' }, { word: '冥想 (명상)', meaning: '고요히 깊은 생각에 잠김' }], radical: '冖', strokeCount: 10 },
  /* 163 治本於農 */
  'ep163-01': { originStory: '물(氵)길을 잘 다듬어 다스린다는(台) 데서, ‘다스리다’를 뜻한다.', vocabulary: [{ word: '政治 (정치)', meaning: '나라를 다스리는 일' }, { word: '治療 (치료)', meaning: '병을 다스려 낫게 함' }], radical: '氵', strokeCount: 8 },
