  'ep163-03': { originStory: '본래 까마귀를 본뜬 글자가 소리를 빌려 쓰여, ‘어조사, …에, …에서’를 뜻한다.', vocabulary: [{ word: '於是 (어시)', meaning: '이에, 그래서' }, { word: '於焉間 (어언간)', meaning: '알지 못하는 사이에' }], radical: '方', strokeCount: 8 },
  'ep163-04': { originStory: '새벽 별(辰) 아래 밭에서 풀(曲)을 갈아엎으며 일한다는 데서, ‘농사’를 뜻한다.', vocabulary: [{ word: '農事 (농사)', meaning: '곡식을 가꾸는 일' }, { word: '農夫 (농부)', meaning: '농사짓는 사람' }], radical: '辰', strokeCount: 13 },
