  'ep164-02': { originStory: '실(玄)이 거듭 쌓여 가까이 있는 것을 가리킨 데서, ‘이, 이것, 여기’를 뜻한다.', vocabulary: [{ word: '今玆 (금자)', meaning: '올해, 이때' }, { word: '念玆在玆 (염자재자)', meaning: '오로지 이것만 생각하고 마음에 둠' }], radical: '玄', strokeCount: 10 },
  'ep164-03': { originStory: '벼(禾)를 한집안(家)을 위해 씨 뿌려 가꾼다는 데서, ‘심다’를 뜻한다.', vocabulary: [{ word: '稼穡 (가색)', meaning: '심고 거두는 농사일' }, { word: '稼動 (가동)', meaning: '기계 따위를 움직여 일함' }], radical: '禾', strokeCount: 15 },
