  'ep165-03': { originStory: '풀과 나무가 무성하게 자라는 따뜻한 쪽을 가리켜, ‘남녘, 남쪽’을 뜻한다.', vocabulary: [{ word: '南北 (남북)', meaning: '남쪽과 북쪽' }, { word: '南向 (남향)', meaning: '남쪽을 향함' }], radical: '十', strokeCount: 9 },
