  'ep168-03': { originStory: '검은(黑) 자리에서 물러나게(出) 한다는 데서, ‘내치다, 물리치다’를 뜻한다.', vocabulary: [{ word: '黜陟 (출척)', meaning: '내치고 올림, 인사 평가' }, { word: '罷黜 (파출)', meaning: '벼슬을 떼고 내쫓음' }], radical: '黑', strokeCount: 17 },
