  'ep170-03': { originStory: '손(彐)으로 벼(禾) 한 다발을 움켜쥔 모습에서, ‘잡다, 쥐다, 지키다’를 뜻한다.', vocabulary: [{ word: '秉燭 (병촉)', meaning: '촛불을 손에 잡음' }, { word: '秉權 (병권)', meaning: '권세를 손에 잡음' }], radical: '禾', strokeCount: 8 },
  'ep170-04': { originStory: '열(十) 개의 눈(目)으로 똑바로 살펴 굽지 않았다는(乚) 데서, ‘곧다, 바르다’를 뜻한다.', vocabulary: [{ word: '正直 (정직)', meaning: '거짓 없이 바름' }, { word: '直線 (직선)', meaning: '곧은 선' }], radical: '目', strokeCount: 8 },
